#nullable enable // autogenerated  

using MVZ2.GameContent.Difficulties;
using MVZ2.GameContent.Effects;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Callbacks;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.zombieCat)]
    public class ZombieCat : EntityBehaviourDefinition
    {
        public ZombieCat(string nsp, string name) : base(nsp, name)
        {
        }
        public override void PostDeath(Entity entity, DeathInfo deathInfo)
        {
            base.PostDeath(entity, deathInfo);
            if (!entity.ShouldTriggerDeathEffects(deathInfo))
                return;
            if (entity.Level.IsIZombie() || entity.RNG.Next(2) == 0)
            {
                entity.SpawnWithParams(VanillaEnemyID.wispFly, entity.GetCenter());
            }
        }
        public override void PreTakeDamage(DamageInput damageInfo, CallbackResult result)
        {
            base.PreTakeDamage(damageInfo, result);
            var entity = damageInfo.Entity;
            if (entity == null)
                return;
            // 按难度读取闪避概率：Easy 0.25 / Normal、Hard 0.5 / Lunatic 0.75  
            float chance = entity.Level.GetZombieCatEvadeChance();
            if (entity.RNG.NextFloat() < chance)
            {
                entity.PlayCrySound(VanillaSoundID.CatHiss);
                entity.Spawn(VanillaEffectID.smokeCluster, entity.GetCenter());
                damageInfo.Multiply(0f);
            }
        }
    }
}
